  {
    ?driver wdt:P118 ?position15.
    ?driver pr:P1628 wd:Q19704270.
  }
  {
    ?driver wdt:P118 ?position16.
    ?driver pr:P1628 wd:Q23045166.
  }
  BIND( (CAST(?position15 AS DECIMAL) + CAST(?position16 AS DECIMAL)) / 2 AS ?avg_pos )
}
GROUP BY ?driver
ORDER BY ASC(?avg_pos)
OFFSET 4
LIMIT 1

